export function getParagonPathById(id: string): ParagonPathData | undefined {
  return PARAGON_PATHS.find((p) => p.id === id);
}

/**
 * Returns all paragon paths available to a character of the given classId.
 * Includes both class-specific paths and universal paths (classId === null).
 */
export function getParagonPathsByClass(classId: string): ParagonPathData[] {
  return PARAGON_PATHS.filter((p) => p.classId === null || p.classId === classId);
}

/**
 * Returns paragon paths available to a character based on both class AND race.
 * Class-specific paths (classId set) must match the character's class.
 * Universal paths (classId === null) are filtered by prerequisite text against
 * the character's race or class name.
 */
export function getParagonPathsForCharacter(classId: string, raceId: string): ParagonPathData[] {
  return PARAGON_PATHS.filter((p) => {
    // Class-specific paths: must match character's class
    if (p.classId !== null) return p.classId === classId;
    // Universal paths (classId === null): check prerequisite against race/class
    if (!p.prerequisite) return true;
    const prereqLower = p.prerequisite.toLowerCase();
    return prereqLower.includes(raceId.toLowerCase()) || prereqLower.includes(classId.toLowerCase());
  });
}
